module RefModule (
	input clk,
	input resetn,
	input up,
	output reg [3:0] count);

	  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
		if (~resetn) count <= 4'b0000;
		else if (up) count <= count + 1;
		else count <= count - 1;
	end
endmodule
